            if (lastCode == '/') {
                continue;
            }
            code = '-';
        } else if (chr == 'B' || (chr == 'P' && nextChar != 'H')) {
            code = '1';
        } else if ((chr == 'D' || chr == 'T') && !arrayContains(new char[] { 'S', 'C', 'Z' }, nextChar)) {
            code = '2';
        } else if (arrayContains(new char[] { 'W', 'F', 'P', 'V' }, chr)) {
            code = '3';
        } else if (arrayContains(new char[] { 'G', 'K', 'Q' }, chr)) {
            code = '4';
        } else if (chr == 'X' && !arrayContains(new char[] { 'C', 'K', 'Q' }, lastChar)) {
            code = '4';
            right.putLeft('S');
            rightLength++;
        } else if (chr == 'S' || chr == 'Z') {
            code = '8';
        } else if (chr == 'C') {
            if (lastCode == '/') {
                if (arrayContains(new char[] { 'A', 'H', 'L', 'O', 'R', 'U', 'K', 'X', 'Q' }, nextChar)) {
                    code = '4';
                } else {
                    code = '8';
                }
            } else {
                if (arrayContains(new char[] { 'S', 'Z' }, lastChar) || !arrayContains(new char[] { 'A', 'H', 'O', 'U', 'K', 'Q', 'X' }, nextChar)) {
                    code = '8';
                } else {
                    code = '4';
                }
            }
        } else if (arrayContains(new char[] { 'T', 'D', 'X' }, chr)) {
            code = '8';
        } else if (chr == 'R') {
            code = '7';
        } else if (chr == 'L') {
            code = '5';
